40	// newWarnCapturingMultipath builds an OPEN, runtime-path-capable Multipath (probers +
41	// newProber + a DynamicScheduler — AddPath's preconditions) whose logger writes JSON
42	// records into the returned buffer at "info" level (so the D53 AUTO-fallback
43	// informational record is captured too, not just WARN/ERROR). It is the D53 test
44	// harness: every scenario below drives AddPath/reconcileDeferred over paths[] and then
45	// inspects buf for the forced-device-bind fallback WARN.
46	func newWarnCapturingMultipath(t *testing.T, paths []config.Path, psk config.Key) (*Multipath, *syncBuffer) {
47		t.Helper()
48		buf := &syncBuffer{}
49		lg, err := log.New("info", buf)
